class Solution:
    def modifiedList(self, nums, head):
        bad = set(nums)
        kept = []
        cur = head
        while cur:
            if cur.val not in bad:
                kept.append(cur.val)
            cur = cur.next
        dummy = ListNode(0)
        tail = dummy
        for v in kept:
            tail.next = ListNode(v)
            tail = tail.next
        return dummy.next

