class Solution:
    def modifiedList(self, nums, head):
        bad = set(nums)
        dummy = ListNode(0, head)
        prev = dummy
        cur = head
        while cur:
            if cur.val in bad:
                prev.next = cur.next
            else:
                prev = cur
            cur = cur.next
        return dummy.next

