var modifiedList = function(nums, head) {
    const bad = new Set(nums);
    const dummy = new ListNode(0, head);
    let prev = dummy;
    let cur = head;
    while (cur) {
        if (bad.has(cur.val)) {
            prev.next = cur.next;
        } else {
            prev = cur;
        }
        cur = cur.next;
    }
    return dummy.next;
};
